WHERE d.del_flag = '0' AND d.tenant_id = #{tenantId}

    AND d.device_code LIKE CONCAT('%', #{deviceCode}, '%')


    AND d.device_name LIKE CONCAT('%', #{deviceName}, '%')


    AND d.bluetooth_name LIKE CONCAT('%', #{bluetoothName}, '%')


    AND d.device_type = #{deviceType}


    AND d.protocol = #{protocol}


    AND d.status = #{status}


    AND d.manufacturer_id = #{manufacturerId}


    AND d.create_time >= #{params.beginTime}


    AND d.create_time <= #{params.endTime}

ORDER BY d.device_id DESC


